import type { ApiMonster } from "../api/types";
import { DEFAULT_NEW_COMBATANT, DND_API_HOST } from "../constants";
import type { Combatant, NewCombatant, SavedPlayer } from "../types";

export function generateId(): string {
  // Generate a random id: 16 characters, URL-safe
  return [1, 2, 3, 4, 5, 6, 7, 8, 9, 0]
    .map(() => Math.random().toString(36).slice(2))
    .join("")
    .slice(0, 16);
}

// Monotonically incrementing counter for combatant numeric IDs.
// Using Date.now() as base ensures no collision with IDs stored in previous sessions.
let _combatantIdCounter = Date.now();

export function generateCombatantId(): number {
  return ++_combatantIdCounter;
}

export function safeParse<T>(raw: string | null): T[] {
  if (!raw) return [] as T[];
  try {
    return JSON.parse(raw) as T[];
  } catch {
    return [] as T[];
  }
}

export function safeStringify<T>(data: T[]): string {
  try {
    return JSON.stringify(data);
  } catch {
    return "[]";
  }
}

export function getStatModifier(stat?: number) {
  if (!stat) return undefined;
  return Math.floor((stat - 10) / 2);
}

export function getAbilityModifier(score: number) {
  const num = score || 10;
  const mod = getStatModifier(num);
  return mod && mod >= 0 ? `+${mod}` : `${mod}`;
};

export function getApiImageUrl(monster: ApiMonster) {
  return `${DND_API_HOST}${monster.image}`;
}

export function safeParseInt(strNumber: string, allowNegative: boolean = false) {
  const result = parseInt(strNumber);
  if (isNaN(result)) return undefined;
  if (!allowNegative && result < 0) return undefined;
  return result;
}

/**
 * Converts an index to a letter identifier (A, B, C, ..., Z, AA, AB, ...)
 * Index 0 = A, Index 25 = Z, Index 26 = AA, etc.
 */
export function indexToLetter(index: number): string {
  let result = "";
  let num = index;

  do {
    result = String.fromCharCode(65 + (num % 26)) + result;
    num = Math.floor(num / 26) - 1;
  } while (num >= 0);

  return result;
}

/**
 * Converts a timestamp to a human-readable relative time or absolute date
 * - "just now" for < 1 minute
 * - "X minutes ago" for < 1 hour
 * - "X hours ago" for < 24 hours
 * - "at 5:15 PM on 03/11" for older dates
 */
export function getReadableTimestamp(timestamp: number | Date): string {
  const now = new Date();
  const date = timestamp instanceof Date ? timestamp : new Date(timestamp);

  const diffMs = now.getTime() - date.getTime();
  const diffMinutes = Math.floor(diffMs / (1000 * 60));
  const diffHours = Math.floor(diffMs / (1000 * 60 * 60));

  // Less than 1 minute
  if (diffMinutes < 1) {
    return "just now";
  }

  // Less than 1 hour
  if (diffMinutes < 60) {
    return `${diffMinutes} ${diffMinutes === 1 ? "minute" : "minutes"} ago`;
  }

  // Less than 24 hours
  if (diffHours < 24) {
    return `${diffHours} ${diffHours === 1 ? "hour" : "hours"} ago`;
  }

  // Format time (e.g., "5:15 PM")
  const hours = date.getHours();
  const minutes = date.getMinutes();
  const ampm = hours >= 12 ? "PM" : "AM";
  const displayHours = hours % 12 || 12;
  const displayMinutes = minutes.toString().padStart(2, "0");
  const timeString = `${displayHours}:${displayMinutes} ${ampm}`;

  // Format date (e.g., "03/11")
  const month = (date.getMonth() + 1).toString().padStart(2, "0");
  const day = date.getDate().toString().padStart(2, "0");

  // If it's within the current year, omit the year
  if (date.getFullYear() === now.getFullYear()) {
    return `at ${timeString} on ${month}/${day}`;
  }

  // If it's from a previous year, include the year
  const year = date.getFullYear();
  return `at ${timeString} on ${month}/${day}/${year}`;
}

export function isNewCombatantInvalid(newCombatant: NewCombatant): boolean {
  return (
    newCombatant.name === "" ||
    !newCombatant.ac || newCombatant.ac <= 0 ||
    !newCombatant.hp || newCombatant.hp <= 0 ||
    newCombatant.initiativeGroups.length === 0 ||
    newCombatant.initiativeGroups.some((g) => g.initiative === "" || g.count === "")
  );
}

export function generateDefaultNewCombatant() {
  return {
    ...DEFAULT_NEW_COMBATANT,
    id: generateId()
  }
}

/**
 * Builds an array of Combatant objects from a list of SavedPlayers,
 * used when auto-adding players at new combat creation time.
 * Mirrors the core logic of prepareCombatantList in useCombatantStore.
 */
export function buildPlayerCombatantsForFight(players: SavedPlayer[]): Combatant[] {
  const result: Combatant[] = [];

  for (const player of players) {
    if (!player.name || !player.hp) continue;
    const groups = player.initiativeGroups;
    if (groups.length === 0) continue;

    const totalCount = groups.reduce((sum, g) => sum + (parseInt(g.count) || 0), 0);
    if (totalCount === 0) continue;

    let globalIndex = 0;
    for (const group of groups) {
      const count = parseInt(group.count) || 1;
      for (let i = 0; i < count; i++) {
        const displayName = totalCount > 1
          ? `${player.name} ${indexToLetter(globalIndex)}`
          : player.name;
        result.push({
          id: generateCombatantId(),
          name: player.name,
          displayName,
          initiative: parseInt(group.initiative) || 0,
          conditions: [],
          deathSaves: { successes: 0, failures: 0 },
          groupIndex: globalIndex,
          templateOrigin: { origin: "player_library", id: player.id },
          color: player.color,
          hp: player.hp,
          maxHp: player.maxHp ?? player.hp,
          ac: player.ac,
          imageUrl: player.imageUrl,
          externalResourceUrl: player.externalResourceUrl,
        });
        globalIndex++;
      }
    }
  }

  return result.sort((a, b) => b.initiative - a.initiative);
}

/**
 * Returns a color class based on HP percentage
 * - > 50%: green
 * - 26-50%: yellow
 * - ≤ 25%: red
 *
 * Tailwind safelist: bg-green-500 bg-yellow-500 bg-red-500 text-green-400 text-yellow-400 text-red-400
 */
export function getHpColorClass(hp: number, maxHp: number, type: 'bg' | 'text' = 'text'): string {
  const pct = maxHp > 0 ? (hp / maxHp) * 100 : 0;
  const color = pct > 50 ? 'green' : pct > 25 ? 'yellow' : 'red';
  const shade = type === 'bg' ? '500' : '400';
  return `${type}-${color}-${shade}`;
}

